 1→package com.yottastudios.ns.collabspace.subscription.consumer;
 2→
 3→import cn.hutool.json.JSONUtil;
 4→import com.rabbitmq.client.Channel;
 5→import com.yottastudios.ns.collabspace.subscription.manager.DocSubscriptionNotifyManager;
 6→import com.yottastudios.ns.collabspace.subscription.mq.dto.DocSubscriptionNotifyMsg;
 7→import jakarta.annotation.Resource;
 8→import lombok.extern.slf4j.Slf4j;
 9→import org.springframework.amqp.core.Message;
10→import org.springframework.amqp.rabbit.annotation.RabbitListener;
11→import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
12→import org.springframework.stereotype.Component;
13→
14→import java.io.IOException;
15→
16→import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.DOC_SUBSCRIPTION_NOTIFY_QUEUE;
17→
18→@Slf4j
19→@Component
20→@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
21→public class DocSubscriptionNotifyConsumer {
22→
23→    @Resource
24→    private DocSubscriptionNotifyManager docSubscriptionNotifyManager;
25→
26→    @RabbitListener(queues = DOC_SUBSCRIPTION_NOTIFY_QUEUE)
27→    public void handle(Message message, Channel channel) throws IOException {
28→        long deliveryTag = message.getMessageProperties().getDeliveryTag();
29→        String body = new String(message.getBody());
30→        log.info("[订阅通知] 收到 MQ 消息: {}", body);
31→        try {
32→            DocSubscriptionNotifyMsg msg = JSONUtil.toBean(body, DocSubscriptionNotifyMsg.class);
33→            docSubscriptionNotifyManager.handleDocUpdate(msg);
34→            channel.basicAck(deliveryTag, false);
35→        } catch (Exception e) {
36→            log.error("[订阅通知] 消费 MQ 消息失败: {}", body, e);
37→            channel.basicNack(deliveryTag, false, false);
38→        }
39→    }
40→}
