 1→package com.yottastudios.ns.collabspace.subscription.mq;
 2→
 3→import cn.hutool.json.JSONUtil;
 4→import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
 5→import com.yottastudios.ns.collabspace.shared.filter.MDCFilter;
 6→import com.yottastudios.ns.collabspace.shared.mq.RabbitMqSender;
 7→import com.yottastudios.ns.collabspace.subscription.mq.dto.DocSubscriptionNotifyMsg;
 8→import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
 9→import jakarta.annotation.Resource;
10→import lombok.extern.slf4j.Slf4j;
11→import org.slf4j.MDC;
12→import org.springframework.stereotype.Component;
13→import org.springframework.transaction.support.TransactionSynchronization;
14→import org.springframework.transaction.support.TransactionSynchronizationManager;
15→
16→/**
17→ * 向订阅通知队列发布文档更新消息。
18→ * 发送时机：事务提交后（afterCommit），避免 DB 未提交即发 MQ。
19→ */
20→@Slf4j
21→@Component
22→public class DocSubscriptionNotifyPublisher {
23→
24→    @Resource
25→    private RabbitMqSender rabbitMqSender;
26→
27→    /**
28→     * 发布文档更新通知消息。
29→     * 若当前不在事务中，则直接发送。
30→     *
31→     * @param spaceNode  发生变更的文档节点
32→     * @param operatorId 操作人 ID（通知时排除该用户），可为 null
33→     */
34→    public void publishDocUpdate(SpaceNodeEntity spaceNode, Long operatorId) {
35→        if (spaceNode == null) {
36→            return;
37→        }
38→        String traceId = MDC.get(MDCFilter.TRACE_ID);
39→        DocSubscriptionNotifyMsg msg = DocSubscriptionNotifyMsg.builder()
40→                .spaceNodeId(spaceNode.getId())
41→                .spaceNodeName(spaceNode.getName())
42→                .spaceId(spaceNode.getSpaceId())
43→                .spaceNodeType(spaceNode.getType())
44→                .operatorId(operatorId)
45→                .traceId(traceId)
46→                .build();
47→
48→        String msgJson = JSONUtil.toJsonStr(msg);
49→
50→        if (TransactionSynchronizationManager.isActualTransactionActive()) {
51→            TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
52→                @Override
53→                public void afterCommit() {
54→                    doSend(msgJson, spaceNode.getId());
55→                }
56→            });
57→        } else {
58→            doSend(msgJson, spaceNode.getId());
59→        }
60→    }
61→
62→    private void doSend(String msgJson, Long spaceNodeId) {
63→        try {
64→            rabbitMqSender.directSend(
65→                    QueueConfig.DOC_SUBSCRIPTION_NOTIFY_EXCHANGE,
66→                    QueueConfig.DOC_SUBSCRIPTION_NOTIFY_KEY,
67→                    msgJson
68→            );
69→            log.info("[订阅通知] 已发布文档更新通知 spaceNodeId={}", spaceNodeId);
70→        } catch (Exception e) {
71→            log.error("[订阅通知] 发布文档更新通知失败 spaceNodeId={}", spaceNodeId, e);
72→        }
73→    }
74→}
