 90→    public void handleDocUpdate(DocSubscriptionNotifyMsg msg) {
 91→        Long spaceNodeId = msg.getSpaceNodeId();
 92→        String spaceNodeName = msg.getSpaceNodeName();
 93→        Long operatorId = msg.getOperatorId();
 94→        String traceId = msg.getTraceId();
 95→
 96→        // 1. 查询订阅该文档的所有用户
 97→        List<DocSubscriptionEntity> subscribers = docSubscriptionService.listBySpaceNodeId(spaceNodeId);
 98→        if (subscribers.isEmpty()) {
 99→            log.info("{} 无订阅者，跳过 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
100→            return;
101→        }
102→
103→        // 2. 过滤掉操作人自身
104→        Set<Long> subscriberIds = subscribers.stream()
105→                .map(DocSubscriptionEntity::getUserId)
106→                .collect(Collectors.toSet());
107→        if (operatorId != null) {
108→            subscriberIds.remove(operatorId);
109→        }
110→        if (subscriberIds.isEmpty()) {
111→            log.info("{} 过滤操作人后无订阅者 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
112→            return;
113→        }
114→
115→        // 3. 权限校验：取与有读权限用户的交集
116→        List<Long> permittedUserIds = spaceNodeUserRoleCacheQueryManager
117→                .listUserIdsBySpaceNodeIdsAndMinRole(List.of(spaceNodeId), NodeRoleLevel.READER);
118→        Set<Long> permittedSet = new HashSet<>(permittedUserIds);
119→        subscriberIds.retainAll(permittedSet);
120→        if (subscriberIds.isEmpty()) {
121→            log.info("{} 权限校验后无目标用户 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId);
122→            return;
123→        }
124→
125→        // 4. 批量获取用户信息，避免循环内逐个查询（用于 IM 推送）
126→        Map<Long, UserSimpleInfoVo> userInfoMap = new HashMap<>();
127→        try {
128→            List<UserSimpleInfoVo> allUsers = apitableGrpcClientService.getAllValidUsers(-1L);
129→            for (UserSimpleInfoVo u : allUsers) {
130→                if (u.getId() != null) {
131→                    userInfoMap.put(u.getId(), u);
132→                }
133→            }
134→        } catch (Exception e) {
135→            log.warn("{} 批量获取用户信息失败，IM 推送将跳过 traceId={}", LOG_PREFIX, traceId, e);
136→        }
137→
138→        // 5. 逐用户处理：节流 + 保存通知 + IM 推送
139→        List<Long> notifiedUserIds = new ArrayList<>();
140→        for (Long userId : subscriberIds) {
141→            // 5a. Redis 节流：同一文档同一用户 300s 内只推一次
142→            String throttleKey = THROTTLE_KEY_PREFIX + spaceNodeId + ":" + userId;
143→            Boolean isFirstPush = stringRedisTemplate.opsForValue()
144→                    .setIfAbsent(throttleKey, "1", THROTTLE_TTL_SECONDS, TimeUnit.SECONDS);
145→            if (!Boolean.TRUE.equals(isFirstPush)) {
146→                log.debug("{} 节流跳过 spaceNodeId={} userId={}", LOG_PREFIX, spaceNodeId, userId);
147→                continue;
148→            }
149→
150→            // 5b. 保存通知记录
151→            DocSubscriptionNotificationEntity notification = DocSubscriptionNotificationEntity.builder()
152→                    .userId(userId)
153→                    .spaceNodeId(spaceNodeId)
154→                    .spaceNodeName(spaceNodeName)
155→                    .isRead(0)
156→                    .build();
157→            docSubscriptionNotificationService.save(notification);
158→
159→            // 5c. IM 推送计数与分发
160→            String imCountKey = IM_COUNT_KEY_PREFIX + userId;
161→            Long imCount = stringRedisTemplate.opsForValue().increment(imCountKey);
162→            if (imCount == null) {
163→                imCount = 1L;
164→            }
165→            if (imCount == 1L) {
166→                // 首次计数，设置 TTL
167→                stringRedisTemplate.expire(imCountKey, IM_COUNT_TTL_SECONDS, TimeUnit.SECONDS);
168→            }
169→
170→            if (imCount > IM_COUNT_AGGREGATE_THRESHOLD) {
171→                // 超过 10 次，跳过单独推送（聚合消息已在第 10 次发出）
172→                log.debug("{} IM 计数超阈值，跳过单独推送 userId={} count={}", LOG_PREFIX, userId, imCount);
173→            } else if (imCount.equals(IM_COUNT_AGGREGATE_THRESHOLD)) {
174→                // 第 10 次：发送聚合提示消息
175→                sendAggregateImMsg(userId, userInfoMap, traceId);
176→            } else {
177→                // 1~9 次：发送正常单条消息
178→                sendNormalImMsg(userId, spaceNodeId, spaceNodeName, userInfoMap, traceId);
179→            }
180→
181→            notifiedUserIds.add(userId);
182→        }
183→
184→        // 6. WebSocket 推送给所有命中用户
185→        if (!notifiedUserIds.isEmpty()) {
186→            pushViaWebSocket(notifiedUserIds, spaceNodeId, spaceNodeName, traceId);
187→        }
188→
189→        log.info("{} 处理完成 spaceNodeId={} notifiedCount={} traceId={}",
190→                LOG_PREFIX, spaceNodeId, notifiedUserIds.size(), traceId);
191→    }
