193→    /**
194→     * WebSocket 推送订阅更新事件
195→     */
196→    private void pushViaWebSocket(List<Long> userIds, Long spaceNodeId, String spaceNodeName, String traceId) {
197→        try {
198→            Map<String, Object> payload = new HashMap<>(4);
199→            payload.put("spaceNodeId", String.valueOf(spaceNodeId));
200→            payload.put("spaceNodeName", spaceNodeName);
201→            WebSocketResponseModel responseModel = WebSocketResponseModel.builder()
202→                    .message(MessageTypeEnum.SUBSCRIPTION_UPDATE.getDesc())
203→                    .status(200)
204→                    .type(MessageTypeEnum.SUBSCRIPTION_UPDATE.getType())
205→                    .data(payload)
206→                    .build();
207→            String wsMsg = objectMapper.writeValueAsString(responseModel);
208→            int sent = webSocketHandler.sendUsersToWebSocketClient(wsMsg, userIds);
209→            log.info("{} WebSocket 推送完成 spaceNodeId={} targetCount={} actualSent={} traceId={}",
210→                    LOG_PREFIX, spaceNodeId, userIds.size(), sent, traceId);
211→        } catch (Exception e) {
212→            log.error("{} WebSocket 推送失败 spaceNodeId={} traceId={}", LOG_PREFIX, spaceNodeId, traceId, e);
213→        }
214→    }
