242→    /**
243→     * 根据配置的 channel 向指定用户发送 IM 消息（knock 或 mm）
244→     */
245→    private void sendImMsg(Long userId, String title, String content,
246→                           Map<Long, UserSimpleInfoVo> userInfoMap, String traceId) {
247→        UserSimpleInfoVo userInfo = userInfoMap.get(userId);
248→        if (userInfo == null) {
