250→            return;
251→        }
252→        // 内网环境走 MM 私信，外网环境走 Knock 机器人
253→        if (constProperties.isInternalNetwork()) {
254→            sendViaMm(userInfo, content, traceId);
255→        } else {
256→            sendViaKnock(userInfo, title, content, traceId);
