260→    /**
261→     * 通过 Knock 机器人发送富文本消息给指定用户
262→     */
263→    private void sendViaKnock(UserSimpleInfoVo userInfo, String title, String content, String traceId) {
264→        try {
265→            String nickName = userInfo.getNickName();
266→            if (StrUtil.isBlank(nickName)) {
267→                log.warn("{} Knock 推送跳过，用户昵称为空 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
268→                return;
269→            }
270→            // 测试环境只打日志不实际发送
271→            if (constProperties.isTestServer()) {
272→                log.info("{} [测试环境-不发送] Knock推送 userId={} nickName={} title={} traceId={}",
273→                        LOG_PREFIX, userInfo.getId(), nickName, title, traceId);
274→                return;
275→            }
276→            knockService.sendRobotRichMsg(List.of(nickName), title, content);
277→            log.info("{} Knock推送成功 userId={} nickName={} traceId={}", LOG_PREFIX, userInfo.getId(), nickName, traceId);
278→        } catch (Exception e) {
279→            log.error("{} Knock推送失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId, e);
280→        }
