283→    /**
284→     * 通过 MM 机器人发送私信给指定用户
285→     */
286→    private void sendViaMm(UserSimpleInfoVo userInfo, String content, String traceId) {
287→        try {
288→            String email = userInfo.getEmail();
289→            if (StrUtil.isBlank(email)) {
290→                log.warn("{} MM 推送跳过，用户邮箱为空 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
291→                return;
292→            }
293→            String botToken = mattermostProperties.getXcollabspaceBotToken();
294→            String botUserId = mattermostProperties.getXcollabspaceBotUserId();
295→            if (StrUtil.isBlank(botToken) || StrUtil.isBlank(botUserId)) {
296→                log.warn("{} MM 推送跳过，botToken 或 botUserId 未配置 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
297→                return;
298→            }
299→            String authToken = "Bearer " + botToken;
300→
301→            // 查询 MM 用户 ID
302→            MattermostUserInfoResp mmUser = mattermostMessageFeign.getUserByEmail(authToken, email);
303→            if (mmUser == null || StrUtil.isBlank(mmUser.getId())) {
304→                log.warn("{} MM 推送跳过，用户在 MM 中不存在 userId={} email={} traceId={}",
305→                        LOG_PREFIX, userInfo.getId(), email, traceId);
306→                return;
307→            }
308→
309→            // 测试环境只打日志不实际发送
310→            if (constProperties.isTestServer()) {
311→                log.info("{} [测试环境-不发送] MM推送 userId={} email={} mmUserId={} traceId={}",
312→                        LOG_PREFIX, userInfo.getId(), email, mmUser.getId(), traceId);
313→                return;
314→            }
315→
316→            // 创建私信频道
317→            MattermostDirectChannelResp channel = mattermostMessageFeign.createDirectMessageChannel(
318→                    authToken, List.of(mmUser.getId(), botUserId));
319→            if (channel == null || StrUtil.isBlank(channel.getId())) {
320→                log.warn("{} MM 推送跳过，创建私信频道失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId);
321→                return;
322→            }
323→
324→            // 发送消息
325→            MattermostPostReq postReq = MattermostPostReq.builder()
326→                    .channelId(channel.getId())
327→                    .message(content)
328→                    .build();
329→            mattermostMessageFeign.createPost(authToken, false, postReq);
330→            log.info("{} MM推送成功 userId={} email={} channelId={} traceId={}",
331→                    LOG_PREFIX, userInfo.getId(), email, channel.getId(), traceId);
332→        } catch (Exception e) {
333→            log.error("{} MM推送失败 userId={} traceId={}", LOG_PREFIX, userInfo.getId(), traceId, e);
334→        }
335→    }
