 49→    @Override
 50→    @Transactional
 51→    public void subscribe(Long userId, Long spaceNodeId) {
 52→        // 校验节点存在且非文件夹
 53→        SpaceNodeEntity node = spaceNodeService.getById(spaceNodeId);
 54→        ExceptionUtil.isNotNull(node, SpaceNodeException.NOT_EXIST);
 55→        if (SpaceNodeTypeEnum.FOLDER.getValue().equals(node.getType())) {
 56→            throw new BusinessException(SpaceNodeException.INVALID_TYPE);
 57→        }
 58→
 59→        // 幂等：已订阅则跳过
 60→        DocSubscriptionEntity existing = docSubscriptionService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
 61→        if (existing != null) {
 62→            log.info("{} 已订阅，跳过 userId={} spaceNodeId={}", LOG_PREFIX, userId, spaceNodeId);
 63→            return;
 64→        }
 65→
 66→        DocSubscriptionEntity entity = DocSubscriptionEntity.builder()
 67→                .userId(userId)
 68→                .spaceNodeId(spaceNodeId)
 69→                .spaceId(node.getSpaceId())
 70→                .build();
 71→        docSubscriptionService.save(entity);
 72→        log.info("{} 订阅成功 userId={} spaceNodeId={} spaceId={}", LOG_PREFIX, userId, spaceNodeId, node.getSpaceId());
 73→    }
