 75→    @Override
 76→    @Transactional
 77→    public void batchSubscribe(Long userId, List<Long> spaceNodeIds) {
 78→        // 过滤文件夹节点
 79→        List<Long> validIds = filterFolders(spaceNodeIds);
 80→        if (validIds.isEmpty()) {
 81→            log.info("{} 批量订阅：全部为文件夹或节点不存在，跳过 userId={}", LOG_PREFIX, userId);
 82→            return;
 83→        }
 84→
 85→        // 排除已订阅的节点
 86→        List<DocSubscriptionEntity> existingList = docSubscriptionService.listByUserIdAndSpaceNodeIds(userId, validIds);
 87→        Set<Long> alreadySubscribed = existingList.stream()
 88→                .map(DocSubscriptionEntity::getSpaceNodeId)
 89→                .collect(Collectors.toSet());
 90→
 91→        // 加载节点信息（用于获取 spaceId）
 92→        List<SpaceNodeEntity> nodes = spaceNodeService.listByIds(validIds);
 93→        Map<Long, SpaceNodeEntity> nodeMap = nodes.stream()
 94→                .collect(Collectors.toMap(SpaceNodeEntity::getId, n -> n));
 95→
 96→        List<DocSubscriptionEntity> toSave = new ArrayList<>();
 97→        for (Long nodeId : validIds) {
 98→            if (alreadySubscribed.contains(nodeId)) {
 99→                continue;
100→            }
101→            SpaceNodeEntity node = nodeMap.get(nodeId);
102→            if (node == null) {
103→                continue;
104→            }
105→            toSave.add(DocSubscriptionEntity.builder()
106→                    .userId(userId)
107→                    .spaceNodeId(nodeId)
108→                    .spaceId(node.getSpaceId())
109→                    .build());
110→        }
111→
112→        if (!toSave.isEmpty()) {
113→            docSubscriptionService.saveBatch(toSave);
114→            log.info("{} 批量订阅成功 userId={} count={}", LOG_PREFIX, userId, toSave.size());
115→        } else {
116→            log.info("{} 批量订阅：无新增记录 userId={}", LOG_PREFIX, userId);
117→        }
118→    }
