201→
202→    @Override
203→    public void dismissConfirmToday(Long userId) {
204→        String key = DISMISS_CONFIRM_KEY_PREFIX + userId;
205→        // TTL 到当日 23:59:59
206→        LocalDateTime endOfDay = LocalDateTime.of(LocalDate.now(), LocalTime.MAX);
207→        Duration ttl = Duration.between(LocalDateTime.now(), endOfDay);
208→        stringRedisTemplate.opsForValue().set(key, "1", ttl);
209→        log.info("{} 今日不再提示 userId={}", LOG_PREFIX, userId);
210→    }
211→
212→    @Override
213→    public boolean isDismissedToday(Long userId) {
214→        String key = DISMISS_CONFIRM_KEY_PREFIX + userId;
215→        return Boolean.TRUE.equals(stringRedisTemplate.hasKey(key));
216→    }
217→
218→    /**
219→     * 过滤掉文件夹类型节点，返回可订阅的节点 ID 列表。
220→     * 不存在的节点也会被排除（listByIds 不返回不存在记录）。
221→     */
222→    private List<Long> filterFolders(List<Long> spaceNodeIds) {
223→        if (spaceNodeIds.isEmpty()) {
224→            return List.of();
225→        }
226→        List<SpaceNodeEntity> nodes = spaceNodeService.listByIds(spaceNodeIds);
227→        return nodes.stream()
228→                .filter(n -> !SpaceNodeTypeEnum.FOLDER.getValue().equals(n.getType()))
229→                .map(SpaceNodeEntity::getId)
230→                .collect(Collectors.toList());
231→    }
