  3→import cn.hutool.json.JSONUtil;
  4→import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
  5→import com.yottastudios.ns.collabspace.shared.filter.MDCFilter;
  6→import com.yottastudios.ns.collabspace.shared.mq.dto.CollabspaceDocChangeMsg;
  7→import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
  8→import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
  9→import jakarta.annotation.Resource;
 10→import lombok.extern.slf4j.Slf4j;
 11→import org.slf4j.MDC;
 12→import org.springframework.stereotype.Component;
 13→import org.springframework.transaction.support.TransactionSynchronization;
 14→import org.springframework.transaction.support.TransactionSynchronizationManager;
 15→
 16→import java.util.Set;
 17→
 18→/**
 19→ * 向 rag-doc-server 广播文档变动通知。
 20→ * 跳过 FOLDER(1)、LUCKYSHEET(6)、OUTLINE(8)、LINK(10)，
 21→ * 只通知有内容可索引的节点类型。
 22→ * 发送时机：事务提交后（afterCommit），避免 DB 未提交即发 MQ。
 23→ */
 24→@Slf4j
 25→@Component
 26→public class RagDocNotifyPublisher {
 27→
 28→    /** 需要通知的 SpaceNodeTypeEnum 值集合 */
 29→    private static final Set<Integer> SUPPORTED_TYPES = Set.of(
 30→            SpaceNodeTypeEnum.DATASHEET.getValue(),       // 2
 31→            SpaceNodeTypeEnum.FORM.getValue(),            // 3
 32→            SpaceNodeTypeEnum.DASHBOARD.getValue(),       // 4
 33→            SpaceNodeTypeEnum.MIRROR.getValue(),          // 5
 34→            SpaceNodeTypeEnum.AFFINE.getValue(),          // 7
 35→            SpaceNodeTypeEnum.ONLYOFFICE_EXCEL.getValue(), // 9
 36→            SpaceNodeTypeEnum.ONLYOFFICE_WORD.getValue(),  // 11
 37→            SpaceNodeTypeEnum.ONLYOFFICE_PPT.getValue(),   // 12
 38→            SpaceNodeTypeEnum.NEXTCLOUD.getValue()          // 13
 39→    );
 40→
 41→    @Resource
 42→    private RabbitMqSender rabbitMqSender;
 43→
 44→    /**
 45→     * 事务提交后发布文档变动消息。
 46→     * 若当前不在事务中，则直接发送。
 47→     */
 48→    public void publishDocChange(SpaceNodeEntity spaceNode) {
 49→        if (spaceNode == null || !SUPPORTED_TYPES.contains(spaceNode.getType())) {
 50→            return;
 51→        }
 52→        String spaceId = spaceNode.getSpaceId();
 53→        Long spaceNodeId = spaceNode.getId();
 54→        Integer type = spaceNode.getType();
 55→        String traceId = MDC.get(MDCFilter.TRACE_ID);
 56→
 57→        CollabspaceDocChangeMsg msg = CollabspaceDocChangeMsg.builder()
 58→                .spaceId(spaceId)
 59→                .spaceNodeId(spaceNodeId)
 60→                .type(type)
 61→                .traceId(traceId)
 62→                .build();
 63→
 64→        String msgJson = JSONUtil.toJsonStr(msg);
 65→
 66→        if (TransactionSynchronizationManager.isActualTransactionActive()) {
 67→            TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
 68→                @Override
 69→                public void afterCommit() {
 70→                    doSend(msgJson, spaceNodeId, type);
 71→                }
 72→            });
 73→        } else {
 74→            doSend(msgJson, spaceNodeId, type);
 75→        }
 76→    }
 77→
 78→    /**
 79→     * 事务提交后发布文档删除消息，通知 rag-doc-server 删除 Ragflow 中的对应文档。
 80→     */
 81→    public void publishDocDelete(SpaceNodeEntity spaceNode) {
 82→        if (spaceNode == null || !SUPPORTED_TYPES.contains(spaceNode.getType())) {
 83→            return;
 84→        }
 85→        String spaceId = spaceNode.getSpaceId();
 86→        Long spaceNodeId = spaceNode.getId();
 87→        Integer type = spaceNode.getType();
 88→        String traceId = MDC.get(MDCFilter.TRACE_ID);
 89→
 90→        CollabspaceDocChangeMsg msg = CollabspaceDocChangeMsg.builder()
 91→                .spaceId(spaceId)
 92→                .spaceNodeId(spaceNodeId)
 93→                .type(type)
 94→                .traceId(traceId)
 95→                .build();
 96→
 97→        String msgJson = JSONUtil.toJsonStr(msg);
 98→
 99→        if (TransactionSynchronizationManager.isActualTransactionActive()) {
100→            TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
101→                @Override
102→                public void afterCommit() {
103→                    doSendDelete(msgJson, spaceNodeId, type);
104→                }
105→            });
106→        } else {
107→            doSendDelete(msgJson, spaceNodeId, type);
108→        }
109→    }
110→
111→    private void doSend(String msgJson, Long spaceNodeId, Integer type) {
112→        try {
113→            rabbitMqSender.directSend(
114→                    QueueConfig.COLLABSPACE_DOC_CHANGE_EXCHANGE,
115→                    QueueConfig.COLLABSPACE_DOC_CHANGE_KEY,
116→                    msgJson
117→            );
118→            log.info("已发送文档变动通知, spaceNodeId={}, type={}", spaceNodeId, type);
119→        } catch (Exception e) {
120→            log.error("发送文档变动通知失败, spaceNodeId={}", spaceNodeId, e);
121→        }
122→    }
123→
124→    private void doSendDelete(String msgJson, Long spaceNodeId, Integer type) {
125→        try {
126→            rabbitMqSender.directSend(
127→                    QueueConfig.COLLABSPACE_DOC_DELETE_EXCHANGE,
128→                    QueueConfig.COLLABSPACE_DOC_DELETE_KEY,
129→                    msgJson
130→            );
131→            log.info("已发送文档删除通知, spaceNodeId={}, type={}", spaceNodeId, type);
132→        } catch (Exception e) {
133→            log.error("发送文档删除通知失败, spaceNodeId={}", spaceNodeId, e);
134→        }
135→    }
136→}
