168→    /**
169→     * Nextcloud 分片消费专用 ContainerFactory：
170→     * 使用批量回调 + AUTO ACK（监听方法成功返回后 ack，抛异常后 reject 且不 requeue）。
171→     * 通过 receiveTimeout 控制 2s 收包窗口，同 shard 单消费者保证顺序。
172→     */
173→    @Bean
174→    public SimpleRabbitListenerContainerFactory nextcloudShardBatchContainerFactory(ConnectionFactory connectionFactory,
175→                                                                                    NextcloudProperties nextcloudProperties) {
176→        NextcloudProperties.Callback callback = nextcloudProperties.getCallback();
177→        int batchMaxSize = Math.max(callback.getBatchMaxSize(), 1);
178→        long receiveTimeoutMs = Math.max(callback.getBatchReceiveTimeoutMs(), 1);
179→        int concurrency = Math.max(callback.getConsumerConcurrencyPerShard(), 1);
180→
181→        SimpleRabbitListenerContainerFactory factory = new SimpleRabbitListenerContainerFactory();
182→        factory.setConnectionFactory(connectionFactory);
183→        factory.setConcurrentConsumers(concurrency);
184→        factory.setMaxConcurrentConsumers(concurrency);
185→        factory.setBatchListener(true);
186→        factory.setConsumerBatchEnabled(true);
187→        factory.setBatchSize(batchMaxSize);
188→        factory.setPrefetchCount(batchMaxSize);
189→        factory.setReceiveTimeout(receiveTimeoutMs);
190→        factory.setAcknowledgeMode(AcknowledgeMode.AUTO);
191→        factory.setDefaultRequeueRejected(false);
192→        return factory;
193→    }
