  5→import cn.hutool.core.util.ArrayUtil;
  6→import cn.hutool.core.util.NumberUtil;
  7→import cn.hutool.core.util.ReUtil;
  8→import cn.hutool.core.util.StrUtil;
  9→import cn.hutool.json.JSONObject;
 10→import cn.hutool.json.JSONUtil;
 11→import com.yottastudios.ns.collabspace.base.enums.ParameterException;
 12→import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
 13→import com.baomidou.mybatisplus.core.metadata.IPage;
 14→import com.baomidou.mybatisplus.core.metadata.OrderItem;
 15→import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
 16→import java.util.ArrayList;
 17→import java.util.List;
 18→
 19→/**
 20→ * <p>
 21→ * page helper util.
 22→ * </p>
 23→ *
 24→ * @author Shawn Deng
 25→ */
 26→public class PageHelper {
 27→
 28→    private static final String TOTAL = "total";
 29→
 30→    private static final String PAGE_NO = "pageNo";
 31→
 32→    private static final String PAGE_SIZE = "pageSize";
 33→
 34→    private static final String ORDER = "order";
 35→
 36→    private static final String SORT = "sort";
 37→
 38→    private static final String ASC = "asc";
 39→
 40→    /**
 41→     * convert string to page.
 42→     *
 43→     * @param stringObjectParams string params
 44→     * @param <T>                type
 45→     * @return page
 46→     */
 47→    public static <T> Page<T> convert(String stringObjectParams) {
 48→        ExceptionUtil.isTrue(JSONUtil.isTypeJSONObject(stringObjectParams),
 49→            ParameterException.INCORRECT_ARG);
 50→        JSONObject json = JSONUtil.parseObj(stringObjectParams);
 51→
 52→        int pageNo = 1;
 53→        int pageSize = 20;
 54→
 55→        String pageSizeParam = json.getStr(PAGE_SIZE);
 56→
 57→        if (StrUtil.isNotEmpty(pageSizeParam) && NumberUtil.isNumber(pageSizeParam)) {
 58→            pageSize = NumberUtil.parseInt(pageSizeParam);
 59→        }
 60→
 61→        String pageNoParam = json.getStr(PAGE_NO);
 62→
 63→        if (StrUtil.isNotEmpty(pageNoParam) && NumberUtil.isNumber(pageNoParam)) {
 64→            pageNo = NumberUtil.parseInt(pageNoParam);
 65→        }
 66→
 67→        Page<T> page = new Page<>();
 68→
 69→        page.setCurrent(pageNo);
 70→        page.setSize(pageSize);
 71→
 72→        String total = json.getStr(TOTAL);
 73→        if (StrUtil.isNotEmpty(total) && NumberUtil.isNumber(total)) {
 74→            page.setTotal(NumberUtil.parseInt(total));
 75→        }
 76→
 77→        String orderParam = json.getStr(ORDER);
 78→        String sortParam = json.getStr(SORT);
 79→
 80→        if (StrUtil.isNotEmpty(orderParam) && StrUtil.isNotEmpty(sortParam)) {
 81→
 82→            String[] orders = orderParam.split(",");
 83→            String[] sorts = sortParam.split(",");
 84→            if (ArrayUtil.isNotEmpty(sorts) && ArrayUtil.isNotEmpty(orders)) {
 85→                List<OrderItem> orderItems = new ArrayList<>();
 86→                String createTime = "createTime";
 87→                String updateTime = "updateTime";
 88→                for (int i = 0; i < sorts.length; i++) {
 89→                    String order = orders[i];
 90→                    ExceptionUtil.isTrue(ReUtil.isMatch("^[a-zA-Z_.]*$", order.trim()),
 91→                        ParameterException.INCORRECT_ARG);
 92→                    if (createTime.equals(order)) {
 93→                        order = "createdAt";
 94→                    }
 95→                    if (updateTime.equals(order)) {
 96→                        order = "updatedAt";
 97→                    }
 98→                    if (ASC.equalsIgnoreCase(sorts[i])) {
 99→                        orderItems.add(OrderItem.asc(StrUtil.toUnderlineCase(order)));
100→                    } else {
101→                        orderItems.add(OrderItem.desc(StrUtil.toUnderlineCase(order)));
102→                    }
103→                }
104→                page.addOrder(orderItems);
105→            }
106→        }
107→
108→        return page;
109→    }
110→
111→    public static <T> PageInfo<T> build(IPage<T> page) {
112→        return new PageInfo<>(page.getCurrent(), page.getSize(), page.getTotal(),
113→            page.getRecords());
114→    }
115→
116→    public static <T> PageInfo<T> build(long pageNum, long pageSize, long total, List<T> records) {
117→        return new PageInfo<>(pageNum, pageSize, total, records);
118→    }
119→}
