  1→package com.yottastudios.ns.collabspace.nextcloud.consumer;
  2→
  3→import cn.hutool.json.JSONUtil;
  4→import com.yottastudios.ns.collabspace.core.constants.RedisConstants;
  5→import com.yottastudios.ns.collabspace.nextcloud.dto.NextcloudWebhookTaskDto;
  6→import com.yottastudios.ns.collabspace.nextcloud.service.NextCloudWebhookService;
  7→import com.yottastudios.ns.collabspace.nextcloud.service.NextcloudWebhookWindowMergeService;
  8→import com.yottastudios.ns.collabspace.nextcloud.service.NextcloudWebhookWindowMergeService.MergedBatch;
  9→import com.yottastudios.ns.collabspace.shared.config.QueueConfig;
 10→import com.yottastudios.ns.collabspace.shared.config.properties.NextcloudProperties;
 11→import com.yottastudios.ns.collabspace.shared.holder.UserHolder;
 12→import jakarta.annotation.Resource;
 13→import lombok.extern.slf4j.Slf4j;
 14→import org.springframework.amqp.core.Message;
 15→import org.springframework.amqp.rabbit.annotation.RabbitListener;
 16→import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
 17→import org.springframework.data.redis.core.RedisTemplate;
 18→import org.springframework.stereotype.Component;
 19→
 20→import java.time.Duration;
 21→import java.util.ArrayList;
 22→import java.util.List;
 23→import java.util.Map;
 24→import java.util.Objects;
 25→import java.util.stream.Collectors;
 26→
 27→@Slf4j
 28→@Component
 29→@ConditionalOnProperty(name = {"mq.enabled", "nextcloud.callback.consumer-enabled"}, havingValue = "true", matchIfMissing = true)
 30→public class NextcloudWebhookShardConsumer {
 31→
 32→    @Resource
 33→    private NextCloudWebhookService nextCloudWebhookService;
 34→
 35→    @Resource
 36→    private RedisTemplate<String, Object> redisTemplate;
 37→
 38→    @Resource
 39→    private NextcloudProperties nextcloudProperties;
 40→
 41→    @Resource
 42→    private NextcloudWebhookWindowMergeService nextcloudWebhookWindowMergeService;
 43→
 44→    @RabbitListener(
 45→            queues = QueueConfig.NEXTCLOUD_WEBHOOK_SHARD_QUEUE_0,
 46→            containerFactory = "nextcloudShardBatchContainerFactory",
 47→            concurrency = "1"
 48→    )
 49→    public void consumeShard0(List<Message> messages) {
 50→        consume(messages, 0);
 51→    }
 52→
 53→    @RabbitListener(
 54→            queues = QueueConfig.NEXTCLOUD_WEBHOOK_SHARD_QUEUE_1,
 55→            containerFactory = "nextcloudShardBatchContainerFactory",
 56→            concurrency = "1"
 57→    )
 58→    public void consumeShard1(List<Message> messages) {
 59→        consume(messages, 1);
 60→    }
 61→
 62→    @RabbitListener(
 63→            queues = QueueConfig.NEXTCLOUD_WEBHOOK_SHARD_QUEUE_2,
 64→            containerFactory = "nextcloudShardBatchContainerFactory",
 65→            concurrency = "1"
 66→    )
 67→    public void consumeShard2(List<Message> messages) {
 68→        consume(messages, 2);
 69→    }
 70→
 71→    @RabbitListener(
 72→            queues = QueueConfig.NEXTCLOUD_WEBHOOK_SHARD_QUEUE_3,
 73→            containerFactory = "nextcloudShardBatchContainerFactory",
 74→            concurrency = "1"
 75→    )
 76→    public void consumeShard3(List<Message> messages) {
 77→        consume(messages, 3);
 78→    }
 79→
 80→    private void consume(List<Message> messages, int shard) {
 81→        if (messages == null || messages.isEmpty()) {
 82→            return;
 83→        }
 84→        long batchStart = System.currentTimeMillis();
 85→        UserHolder.init();
 86→        try {
 87→            List<NextcloudWebhookTaskDto> tasks = decodeMessages(messages);
 88→            if (tasks.isEmpty()) {
 89→                return;
 90→            }
 91→            List<NextcloudWebhookTaskDto> deduplicatedTasks = tasks.stream()
 92→                    .filter(Objects::nonNull)
 93→                    .filter(task -> task.getSpaceName() != null)
 94→                    .filter(task -> !isDuplicated(task))
 95→                    .toList();
 96→
 97→            int inCount = deduplicatedTasks.size();
 98→            Map<String, List<NextcloudWebhookTaskDto>> groupedBySpace = deduplicatedTasks.stream()
 99→                    .collect(Collectors.groupingBy(NextcloudWebhookTaskDto::getSpaceName));
100→            int outCount = 0;
101→            int dropCount = 0;
102→            for (Map.Entry<String, List<NextcloudWebhookTaskDto>> entry : groupedBySpace.entrySet()) {
103→                String spaceName = entry.getKey();
104→                MergedBatch mergedBatch = nextcloudWebhookWindowMergeService.mergeBySpaceWindow(spaceName, entry.getValue());
105→                outCount += mergedBatch.totalCount();
106→                dropCount += Math.max(0, entry.getValue().size() - mergedBatch.totalCount());
107→                nextCloudWebhookService.handleWebhookMergedBatch(mergedBatch);
108→            }
109→
110→            long flushMs = System.currentTimeMillis() - batchStart;
111→            long configuredBatchReceiveTimeoutMs = Math.max(1L, nextcloudProperties.getCallback().getBatchReceiveTimeoutMs());
112→            log.info("Nextcloud webhook batch flushed: shard={}, window_in_count={}, window_out_count={}, merge_drop_count={}, batch_flush_ms={}, space_count={}, configured_batch_receive_timeout_ms={}",
113→                    shard, inCount, outCount, dropCount, flushMs, groupedBySpace.size(), configuredBatchReceiveTimeoutMs);
114→        } catch (Exception e) {
115→            log.error("Nextcloud webhook batch consume failed: shard={}, batch_fail_count=1, error={}", shard, e.getMessage(), e);
116→            throw new RuntimeException(e);
117→        } finally {
118→            UserHolder.remove();
119→        }
120→    }
121→
122→    private List<NextcloudWebhookTaskDto> decodeMessages(List<Message> messages) {
123→        List<NextcloudWebhookTaskDto> tasks = new ArrayList<>(messages.size());
124→        for (Message message : messages) {
125→            if (message == null || message.getBody() == null) {
126→                continue;
127→            }
128→            try {
129→                String body = new String(message.getBody());
130→                NextcloudWebhookTaskDto task = JSONUtil.toBean(body, NextcloudWebhookTaskDto.class);
131→                if (task != null) {
132→                    tasks.add(task);
133→                }
134→            } catch (Exception e) {
135→                log.error("Nextcloud webhook decode failed, reject whole batch for retry, error={}", e.getMessage(), e);
136→                throw new IllegalArgumentException("nextcloud webhook decode failed", e);
137→            }
138→        }
139→        return tasks;
140→    }
141→
142→    /**
143→     * 完全重复消息防抖：用 Redis SETNX + 短 TTL 判断同一消息是否已处理过。
144→     * 业务幂等仍以 NextCloudWebhookService 内的校验逻辑为主。
145→     */
146→    private boolean isDuplicated(NextcloudWebhookTaskDto task) {
147→        int ttl = nextcloudProperties.getCallback().getIdempotencyTtlSeconds();
148→        if (ttl <= 0) {
149→            return false;
150→        }
151→        String key = RedisConstants.getNextcloudWebhookIdempotentKey(task.fingerprint());
152→        Boolean absent = redisTemplate.opsForValue().setIfAbsent(key, "1", Duration.ofSeconds(ttl));
153→        return absent != null && !absent;
154→    }
155→}
