 1→package com.yottastudios.ns.collabspace.workspace.consumer;
 2→
 3→import com.rabbitmq.client.Channel;
 4→import com.yottastudios.ns.collabspace.workspace.service.thirdparty.impl.DefaultAppUploadDataServiceImpl;
 5→import jakarta.annotation.Resource;
 6→import lombok.extern.slf4j.Slf4j;
 7→import org.springframework.amqp.core.Message;
 8→import org.springframework.amqp.rabbit.annotation.RabbitListener;
 9→import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
10→import org.springframework.stereotype.Component;
11→
12→import java.io.IOException;
13→
14→import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.THIRD_APP_UPLOAD_UPDATE_QUEUE;
15→
16→@Slf4j
17→@Component
18→@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
19→public class ThirdAppUploadUpdateConsumer {
20→
21→    @Resource(name = "defaultAppUploadDataServiceImpl")
22→    private DefaultAppUploadDataServiceImpl defaultAppUploadDataService;
23→
24→    @RabbitListener(queues = THIRD_APP_UPLOAD_UPDATE_QUEUE)
25→    public void handle(Message message, Channel channel) throws IOException {
26→        long deliveryTag = message.getMessageProperties().getDeliveryTag();
27→        String body = new String(message.getBody());
28→        log.info("收到 uploadUpdateTime MQ 消息: {}", body);
29→        try {
30→            defaultAppUploadDataService.doUploadUpdateTime(body);
31→            channel.basicAck(deliveryTag, false);
32→        } catch (Exception e) {
33→            log.error("消费 uploadUpdateTime MQ 消息失败: {}", body, e);
34→            channel.basicNack(deliveryTag, false, true);
35→            throw e;
36→        }
37→    }
38→}
