 1→package com.yottastudios.ns.collabspace.interfaces.eventbus.model;
 2→
 3→import cn.hutool.core.util.BooleanUtil;
 4→import cn.hutool.json.JSONUtil;
 5→import com.rabbitmq.client.Channel;
 6→import com.yottastudios.ns.collabspace.shared.holder.UserHolder;
 7→import jakarta.annotation.Resource;
 8→import lombok.extern.slf4j.Slf4j;
 9→import org.slf4j.MDC;
10→import org.springframework.amqp.core.Message;
11→import org.springframework.data.redis.core.RedisTemplate;
12→
13→import java.io.IOException;
14→import java.util.concurrent.TimeUnit;
15→
16→import static com.yottastudios.ns.collabspace.shared.filter.MDCFilter.TRACE_ID;
17→
18→@Slf4j
19→public abstract class BaseEventListener<T extends BaseEvent> {
20→    @Resource
21→    protected RedisTemplate<String, Object> redisTemplate;
22→
23→    public void handleMessage(Message message, Channel channel, String queueName, Class<? extends BaseEvent> eventClass) throws IOException {
24→        long deliveryTag = message.getMessageProperties().getDeliveryTag();
25→        String body;
26→
27→        try {
28→            UserHolder.init();
29→            body = new String(message.getBody());
30→            BaseEvent baseEvent = (BaseEvent) JSONUtil.toBean(body, eventClass);
31→            T event = (T) baseEvent;
32→
33→            String traceId = event.getTraceId();
34→            MDC.put(TRACE_ID, traceId);
35→
36→            log.info("收到消息: queue={}, eventType={}, body={}", queueName, event.getEventType(), body);
37→
38→            if (isMessageDuplicate(queueName, traceId, deliveryTag)) {
39→                log.info("跳过重复消息: traceId={}", traceId);
40→                channel.basicAck(deliveryTag, false);
41→                return;
42→            }
43→            Long userId = event.getOperatorId();
44→            if (userId == null) {
45→                log.warn("userId is null");
46→            }
47→            UserHolder.set(userId);
48→            handleEvent(event);
49→
50→            channel.basicAck(deliveryTag, false);
51→        } catch (Exception e) {
52→            log.error("处理消息异常: queue={}", queueName, e);
53→            boolean retry = shouldRetry(e);
54→            channel.basicNack(deliveryTag, false, retry);
55→            // todo 推到死信处理?
56→        } finally {
57→            UserHolder.remove();
58→            MDC.remove(TRACE_ID);
59→        }
60→    }
61→
62→    protected boolean shouldRetry(Exception e) {
63→        // 默认不重试
64→        return false;
65→    }
66→
67→    // 业务逻辑, 子类实现
68→    protected abstract void handleEvent(T event);
69→
70→    private boolean isMessageDuplicate(String queue, String traceId, long deliveryTag) {
71→        String lockKey = queue + ":" + traceId + ":" + deliveryTag;
72→        Boolean lock = redisTemplate.opsForValue().setIfAbsent(lockKey, "1", 1, TimeUnit.DAYS);
73→        return BooleanUtil.isFalse(lock);
74→    }
75→}
